// ══════════════════════════════════════════════════════════
// CONFIGURATION — Edit these values for your workspace
// ══════════════════════════════════════════════════════════
const CONFIG = {
  // Clarify workspace slug (from your Clarify URL)
  clarifyWorkspace: 'your-workspace-slug',

  // Clarify API key (from Settings → API Keys)
  clarifyApiKey: 'YOUR_CLARIFY_API_KEY',

  // How many transcripts to process per run (max 50)
  batchSize: 50,

  // Optional: override date range (ISO 8601). Leave null to use auto sync state.
  // Useful for testing or targeting a specific window.
  startDate: null,  // e.g. '2026-03-01T00:00:00Z'
  endDate: null,    // e.g. '2026-03-15T00:00:00Z'
};
// ══════════════════════════════════════════════════════════

// Load sync state from workflow static data.
// On first run, lastSyncDate is null — Fireflies returns all transcripts (oldest first).
const staticData = $getWorkflowStaticData('global');
return [{
  json: {
    ...CONFIG,
    lastSyncDate: CONFIG.startDate || staticData.lastSyncDate || null,
    endDate: CONFIG.endDate || null,
    syncedCount: (staticData.syncedIds || []).length,
    isFirstRun: !staticData.lastSyncDate
  }
}];

// Get last sync date from workflow static data
const staticData = $getWorkflowStaticData('global');
const lastSyncDate = staticData.lastSyncDate || null;
const syncedIds = new Set(staticData.syncedIds || []);

// Filter out already-synced transcripts
const transcripts = $input.first().json.data?.transcripts || [];
const newTranscripts = transcripts.filter(t => !syncedIds.has(t.id));

if (newTranscripts.length === 0) {
  return [{ json: { skip: true, message: 'No new transcripts', count: 0 } }];
}

// Pass each transcript as a separate item for the loop
return newTranscripts.map(t => ({
  json: {
    skip: false,
    id: t.id,
    title: t.title,
    date: t.dateString || (t.date ? new Date(t.date).toISOString() : null),
    duration: t.duration || 30,
    organizer_email: t.organizer_email,
    calendar_id: t.calendar_id,
    participants: t.participants || [],
    speakers: t.speakers || [],
    meeting_attendees: (t.meeting_attendees || []).map(a => ({
      email: a.email,
      name: a.displayName || a.name || a.email || 'Unknown'
    })).filter(a => a.email)
  }
}));

// Convert Fireflies transcript → Clarify format
// Fireflies: sentence-level timestamps in SECONDS
// Clarify: word-level timestamps in seconds, grouped by speaker

const transcript = $input.first().json.data?.transcript;
if (!transcript || !transcript.sentences || transcript.sentences.length === 0) {
  return [{ json: { skip: true, reason: 'No sentences', id: $('Filter Already Synced').item.json.id } }];
}

const sentences = transcript.sentences;
const speakers = transcript.speakers || [];

// Build speaker name → ID map
const speakerIdMap = {};
speakers.forEach((s, i) => {
  speakerIdMap[s.name] = s.id != null ? parseInt(s.id, 10) : i;
});
let nextSpeakerId = speakers.length;

// Group consecutive sentences by speaker, split into words
const segments = [];
let currentSegment = null;

for (const sentence of sentences) {
  const speakerName = sentence.speaker_name || 'Unknown';
  const text = sentence.text || sentence.raw_text || '';
  const startSec = sentence.start_time || 0;
  const endSec = sentence.end_time || startSec;

  if (!currentSegment || currentSegment.speaker !== speakerName) {
    if (currentSegment && currentSegment.words.length > 0) segments.push(currentSegment);
    if (!(speakerName in speakerIdMap)) speakerIdMap[speakerName] = nextSpeakerId++;
    currentSegment = { speaker: speakerName, speaker_id: speakerIdMap[speakerName], language: null, words: [] };
  }

  const words = text.split(/\s+/).filter(Boolean);
  if (words.length === 0) continue;

  const durationSec = endSec - startSec;
  const wordDurationSec = durationSec / words.length;

  for (let i = 0; i < words.length; i++) {
    currentSegment.words.push({
      text: words[i],
      start_timestamp: startSec + i * wordDurationSec,
      end_timestamp: startSec + (i + 1) * wordDurationSec,
      language: null,
      confidence: null
    });
  }
}
if (currentSegment && currentSegment.words.length > 0) segments.push(currentSegment);

// Build meeting data
const sourceItem = $('Filter Already Synced').item.json;
const startDate = transcript.dateString || sourceItem.date;
const durationMin = transcript.duration || sourceItem.duration || 30;
const endDate = new Date(new Date(startDate).getTime() + durationMin * 60 * 1000).toISOString();

// Get attendees with emails
const attendees = (transcript.meeting_attendees || [])
  .filter(a => a.email)
  .map(a => ({
    email: a.email.toLowerCase(),
    name: a.displayName || a.name || a.email || 'Unknown'
  }));

return [{
  json: {
    skip: false,
    firefliesId: transcript.id,
    calendarId: transcript.calendar_id || null,
    title: transcript.title || 'Untitled Meeting',
    start: startDate,
    end: endDate,
    attendees: attendees,
    participants: attendees.map(a => ({
      email: a.email,
      name: a.name,
      phone_number: null,
      status: 'yes',
      organizer: false
    })),
    transcript: segments,
    segmentCount: segments.length,
    sentenceCount: sentences.length
  }
}];

// Find existing meeting in Clarify or create a new one.
//
// Matching strategy (tightest first):
//   1. Calendar ID match (ical_uid) — automatic, no scoring needed
//   2. Multi-signal scoring within a 30-minute window:
//      - Time proximity (0-40 pts, 30 min window)
//      - Title similarity via Jaccard word overlap (0-40 pts)
//      - Participant email overlap (0-30 pts)
//      - Minimum 60 pts AND at least 2 signals required

const prev = $('Convert to Clarify Format').item.json;
const workspace = $('Load Sync State').item.json.clarifyWorkspace;
const apiKey = $('Load Sync State').item.json.clarifyApiKey;
const baseUrl = `https://api.clarify.ai/v1/workspaces/${workspace}`;

// --- Helper: Jaccard word similarity ---
function jaccardSimilarity(title1, title2) {
  if (!title1 || !title2) return 0;
  const words1 = new Set(title1.toLowerCase().replace(/[^a-z0-9 ]/g, '').split(/ +/).filter(w => w.length > 2));
  const words2 = new Set(title2.toLowerCase().replace(/[^a-z0-9 ]/g, '').split(/ +/).filter(w => w.length > 2));
  if (words1.size === 0 || words2.size === 0) return 0;
  let intersection = 0;
  for (const w of words1) { if (words2.has(w)) intersection++; }
  const union = new Set([...words1, ...words2]).size;
  return intersection / union;
}

// --- Step 0: Guard against null/invalid dates ---
if (!prev.start || isNaN(new Date(prev.start).getTime())) {
  // No valid date — skip matching, create new meeting
  const createData = await this.helpers.httpRequest({
    method: 'POST',
    url: `${baseUrl}/objects/meeting/records`,
    headers: { 'Authorization': `api-key ${apiKey}`, 'Content-Type': 'application/json' },
    body: { data: { type: 'meeting', attributes: { title: prev.title, start: prev.start || new Date().toISOString(), end: prev.end || new Date().toISOString(), all_day: false, visibility: 'default', event_id: 'adhoc-fireflies-' + prev.firefliesId, participants: { items: prev.participants } } } },
    json: true,
  });
  return [{ json: { meetingId: createData.data?.id, matched: false, created: true, noDate: true } }];
}

// --- Step 1: Search Clarify meetings within 1 day of transcript ---
const transcriptDate = new Date(prev.start);
const dayBefore = new Date(transcriptDate.getTime() - 24*60*60*1000).toISOString();
const dayAfter = new Date(transcriptDate.getTime() + 24*60*60*1000).toISOString();
const searchParams = `filter[start][Is on or after]=${encodeURIComponent(dayBefore)}&filter[start][Is on or before]=${encodeURIComponent(dayAfter)}&page[limit]=200`;
const searchData = await this.helpers.httpRequest({
  method: 'GET',
  url: `${baseUrl}/objects/meeting/resources?${searchParams}`,
  headers: { 'Authorization': `api-key ${apiKey}` },
  json: true,
});
const candidates = searchData.data || [];

// --- Step 1a: Try calendar ID match first (strongest signal) ---
if (prev.calendarId) {
  const calMatch = candidates.find(item =>
    item.attributes.ical_uid && item.attributes.ical_uid === prev.calendarId
  );
  if (calMatch) {
    return [{ json: { meetingId: calMatch.id, matched: true, matchType: 'calendar_id', matchTitle: calMatch.attributes.title } }];
  }
}

// --- Step 2: Score-based matching (30-minute window) ---
const targetDate = new Date(prev.start).getTime();
const THIRTY_MIN = 30 * 60 * 1000;
const participantEmails = prev.attendees.map(a => a.email.toLowerCase());

let bestMatch = null;
let bestScore = 0;

for (const item of candidates) {
  const attrs = item.attributes;
  let score = 0;
  let signals = 0;

  if (!attrs.start) continue;
  const meetingDate = new Date(attrs.start).getTime();
  const timeDiff = Math.abs(meetingDate - targetDate);
  if (timeDiff > THIRTY_MIN) continue;
  const timeScore = (1 - timeDiff / THIRTY_MIN) * 40;
  score += timeScore;
  if (timeScore > 10) signals++;

  const titleSim = jaccardSimilarity(prev.title, attrs.title);
  const titleScore = titleSim * 40;
  score += titleScore;
  if (titleScore > 10) signals++;

  if (participantEmails.length > 0 && attrs.participants?.items) {
    const meetingEmails = attrs.participants.items.map(p => p.email?.toLowerCase()).filter(Boolean);
    const overlap = participantEmails.filter(e => meetingEmails.includes(e)).length;
    if (overlap > 0) {
      score += Math.min(overlap * 10, 30);
      signals++;
    }
  }

  if (score > bestScore && score >= 60 && signals >= 2) {
    bestScore = score;
    bestMatch = { id: item.id, title: attrs.title, score, signals };
  }
}

if (bestMatch) {
  return [{ json: { meetingId: bestMatch.id, matched: true, matchType: 'scored', matchScore: bestMatch.score, matchSignals: bestMatch.signals, matchTitle: bestMatch.title } }];
}

// --- Step 3: No match — create new meeting ---
const createData = await this.helpers.httpRequest({
  method: 'POST',
  url: `${baseUrl}/objects/meeting/records`,
  headers: { 'Authorization': `api-key ${apiKey}`, 'Content-Type': 'application/json' },
  body: {
    data: {
      type: 'meeting',
      attributes: {
        title: prev.title,
        start: prev.start,
        end: prev.end,
        all_day: false,
        visibility: 'default',
        event_id: 'adhoc-fireflies-' + prev.firefliesId,
        participants: { items: prev.participants }
      }
    }
  },
  json: true,
});

if (!createData.data?.id) {
  throw new Error('Failed to create meeting: ' + JSON.stringify(createData));
}

return [{ json: { meetingId: createData.data.id, matched: false, created: true } }];

// For each attendee email, search for existing Person, create if missing, collect IDs
const attendees = $('Convert to Clarify Format').item.json.attendees || [];
const meetingId = $('Find or Create Meeting').item.json.meetingId;
const workspace = $('Load Sync State').item.json.clarifyWorkspace;
const apiKey = $('Load Sync State').item.json.clarifyApiKey;

if (!meetingId || attendees.length === 0) {
  return [{ json: { meetingId, personIds: [], linked: 0 } }];
}

const hdrs = { 'Authorization': `api-key ${apiKey}`, 'Content-Type': 'application/json' };
const baseUrl = `https://api.clarify.ai/v1/workspaces/${workspace}`;

const personIds = [];

for (const attendee of attendees) {
  try {
    // Search for existing person
    const searchData = await this.helpers.httpRequest({
      method: 'GET',
      url: `${baseUrl}/objects/person/resources?filter[email_addresses][Contains]=${encodeURIComponent(attendee.email)}&page[limit]=1`,
      headers: hdrs,
      json: true,
    });

    if (searchData.data && searchData.data.length > 0) {
      personIds.push(searchData.data[0].id);
      continue;
    }

    // Create new person
    const nameParts = (attendee.name || '').trim().split(/\s+/);
    const nameObj = {};
    if (attendee.name) nameObj.full_name = attendee.name;
    if (nameParts.length >= 2) {
      nameObj.first_name = nameParts[0];
      nameObj.last_name = nameParts.slice(1).join(' ');
    } else if (nameParts.length === 1 && nameParts[0]) {
      nameObj.first_name = nameParts[0];
    }

    const createData = await this.helpers.httpRequest({
      method: 'POST',
      url: `${baseUrl}/objects/person/records`,
      headers: hdrs,
      body: {
        data: {
          type: 'person',
          attributes: {
            email_addresses: { items: [attendee.email] },
            ...(Object.keys(nameObj).length > 0 ? { name: nameObj } : {})
          }
        }
      },
      json: true,
    });
    if (createData.data?.id) {
      personIds.push(createData.data.id);
    }
  } catch (e) {
    // Don't fail the whole sync over one person
  }
}

// Link people to meeting
if (personIds.length > 0) {
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${baseUrl}/objects/meeting/records/${meetingId}/relationships/people`,
      headers: hdrs,
      body: { data: personIds.map(id => ({ type: 'person', id })) },
      json: true,
    });
  } catch (e) {
    // Best effort
  }
}

return [{ json: { meetingId, personIds, linked: personIds.length } }];

// Update workflow static data with synced IDs and timestamp
const staticData = $getWorkflowStaticData('global');
const syncedIds = staticData.syncedIds || [];

// Collect all fireflies IDs that were processed in this run
const items = $('Filter Already Synced').all();
const newIds = items
  .filter(item => !item.json.skip)
  .map(item => item.json.id)
  .filter(Boolean);

// Append new IDs (keep last 10000 to prevent unbounded growth)
const allIds = [...syncedIds, ...newIds].slice(-10000);
staticData.syncedIds = allIds;
staticData.lastSyncDate = new Date().toISOString();
staticData.lastRunStats = {
  date: new Date().toISOString(),
  processed: newIds.length,
  total: items.length
};

return [{
  json: {
    message: `Sync complete. Processed ${newIds.length} transcripts.`,
    lastSyncDate: staticData.lastSyncDate,
    totalSynced: allIds.length
  }
}];

// Mark empty transcripts as synced too so we don't retry them
const staticData = $getWorkflowStaticData('global');
const syncedIds = staticData.syncedIds || [];
const skippedId = $json.id;
if (skippedId) {
  syncedIds.push(skippedId);
  staticData.syncedIds = syncedIds.slice(-10000);
}
return [{ json: { skipped: true, id: skippedId, reason: $json.reason || 'no sentences' } }];
